#[async_trait]
impl<R: AnalyticsEventProjectionRepository> AnalyticsEventEventHandler for AnalyticsEventProjector<R> {

    async fn on_created(&self, event: AnalyticsEventCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = AnalyticsEventProjection::new(
            event.id,
            event.event_type,
            event.user_id,
            event.session_id,
            event.resource_type,
            event.resource_id,
            event.properties,
            event.timestamp,
            event.ip_address,
            event.user_agent,
            event.geographic_data,
            event.processed,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: AnalyticsEventUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.event_type = event.event_type;
            projection.user_id = event.user_id;
            projection.session_id = event.session_id;
            projection.resource_type = event.resource_type;
            projection.resource_id = event.resource_id;
            projection.properties = event.properties;
            projection.timestamp = event.timestamp;
            projection.ip_address = event.ip_address;
            projection.user_agent = event.user_agent;
            projection.geographic_data = event.geographic_data;
            projection.processed = event.processed;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: AnalyticsEventDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

